import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Ad Partner Integration Testing","description":"","frontmatter":{"title":"Ad Partner Integration Testing","slug":"ad-partner-integration-testing"},"headers":[],"relativePath":"marketer-hub/ad-partner-integration-testing.md","filePath":"marketer-hub/ad-partner-integration-testing.md"}'),i={name:"marketer-hub/ad-partner-integration-testing.md"};function n(s,e,l,p,c,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>An essential part of the Ad Partners verification process is to confirm that the integration works as expected and we deliver the best user experience. This enables Branch to guarantee the highest quality of Ad Partnership integrations and verify data accuracy.</p><p>Once we&#39;ve provided you with the Click/Impression Tracking URLs via email, please follow the steps below so we can verify that postback URLs are coming through correctly on your end.</p><h2 id="click-tracking-postback-url-testing" tabindex="-1">Click Tracking &amp; Postback URL Testing <a class="header-anchor" href="#click-tracking-postback-url-testing" aria-label="Permalink to &quot;Click Tracking &amp; Postback URL Testing&quot;">​</a></h2><ol><li>Add the previously emailed tracking link to your system to generate a <strong>ClickID</strong> and <strong>AAID</strong> or <strong>IDFA</strong> specified in the Branch tracking URL, e.g.: <code>https://branchster.app.link/bKzQX2KCcS?%243p=partner_id&amp;%24aaid={aaid}&amp;%24idfa={idfa}&amp;~click_id={click_id}&amp;~secondary_publisher={secondary_publisher}&amp;parameter1={XXX}&amp;parameter2={YYY}&amp;parameter3={ZZZ}</code></li><li>Click on the tracking URL that now contains the filled macro parameters.</li><li>You&#39;ll be redirected to web page with Branch Monster Factory application.</li><li>Please initiate the following actions - <em>Install</em>, <em>Open</em> and <em>Purchase</em> events - following the guide specifications below.</li><li>Once we register those events, we will pass to you a predefined postback with populated parameters.</li><li>Please check your system to ensure we passed the correct postback parameters back to you.</li><li>Notify us via email to verify integration.</li></ol><p>Please refer to the following screenshots below based on the iOS and Android Mobile Platforms per Event Type:</p><h2 id="test-application-branch-monster-factory" tabindex="-1">Test application - Branch Monster Factory <a class="header-anchor" href="#test-application-branch-monster-factory" aria-label="Permalink to &quot;Test application - Branch Monster Factory&quot;">​</a></h2><p>iOS:<a href="https://apps.apple.com/us/app/branch-monster-factory/id917737838?mt=8" target="_blank" rel="noreferrer">https://apps.apple.com/us/app/branch-monster-factory/id917737838?mt=8</a><br> Android: <a href="https://play.google.com/store/apps/details?id=io.branch.branchster" target="_blank" rel="noreferrer">https://play.google.com/store/apps/details?id=io.branch.branchster</a></p><h2 id="install" tabindex="-1">INSTALL <a class="header-anchor" href="#install" aria-label="Permalink to &quot;INSTALL&quot;">​</a></h2><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><p>Tap on the test click URL.<br> At the bottom of page click on <strong>Install Full App</strong> to install the Branch Monster Factory app.<br> You will be redirected to Google Play Store. Click on <code>Install</code> button to initiate INSTALL event</p><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><p>Tap on the test click URL. The iOS prompts to open in App Store.<br> When redirected to App Store click on the <code>Cloud</code> download icon. Once the app is installed the INSTALL event initiated.</p><h2 id="open" tabindex="-1">OPEN <a class="header-anchor" href="#open" aria-label="Permalink to &quot;OPEN&quot;">​</a></h2><h3 id="android-1" tabindex="-1">Android <a class="header-anchor" href="#android-1" aria-label="Permalink to &quot;Android&quot;">​</a></h3><p>To open the Branch Monster Factory app, find it on your Phone or navigate to Google Play and click the <code>Open</code> button. Once the Branch Monster Factory app opens, the OPEN event is initiated.</p><h3 id="ios-1" tabindex="-1">iOS <a class="header-anchor" href="#ios-1" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><p>Make sure the Branch Monster Factory app is installed. Find it on your phone or tap on <code>Open</code> button in App Store<br> Once Monster Factory app opened the OPEN event was initiated.</p><h2 id="purchase" tabindex="-1">PURCHASE <a class="header-anchor" href="#purchase" aria-label="Permalink to &quot;PURCHASE&quot;">​</a></h2><h3 id="android-2" tabindex="-1">Android <a class="header-anchor" href="#android-2" aria-label="Permalink to &quot;Android&quot;">​</a></h3><p>Open the installed Branch Monster Factory app and tap on the <code>Share</code> icon. The share window pops up with multiple options. Tap on the <strong>Copy to clipboard</strong> item. When you see the <strong>Copied to clipboard</strong> notice, the PURCHASE event is initiated.</p><h3 id="ios-2" tabindex="-1">iOS <a class="header-anchor" href="#ios-2" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><p>Open the installed Branch Monster Factory app and tap on the <strong>Share Your Monster link</strong> at the bottom. The share window pops up with multiple options. Tap on the <code>Copy</code> item to initiate PURCHASE event.</p>',23)])])}const m=t(i,[["render",n]]);export{u as __pageData,m as default};
